--
-- Table structure for table `tb_search_statistic`
--

DROP TABLE IF EXISTS `tb_search_statistic`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tb_search_statistic` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `task_id` int(11) unsigned NOT NULL COMMENT '任务ID',
  `issue_ip_total` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '基础IP总数',
  `issue_ip_num` int(11) unsigned NOT NULL COMMENT ' 发布IP数',
  `real_ip_num` int(11) unsigned NOT NULL COMMENT '实际下发IP数',
  `ip_back` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'IP返回数',
  `total_pv` int(11) unsigned NOT NULL COMMENT 'PV总数',
  `pv_back` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'PV返回数',
  `ip_pv_ratio` float(4,2) NOT NULL DEFAULT '0.00' COMMENT 'PV/IP比',
  `issue_sn` int(11) unsigned NOT NULL COMMENT '发布搜索数',
  `real_sn` int(11) unsigned NOT NULL COMMENT '实际下发搜索数',
  `search_back` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '搜索返回数',
  `issue_hao_sn` int(11) unsigned NOT NULL COMMENT 'hao123发布搜索数',
  `real_hao_sn` int(11) unsigned NOT NULL COMMENT 'hao123实际下发搜索数',
  `issue_baidu_sn` int(11) unsigned NOT NULL COMMENT 'baidu发布搜索数',
  `real_baidu_sn` int(11) unsigned NOT NULL COMMENT 'baidu实际下发搜索数',
  `issue_click` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '发布点击数',
  `real_click` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '实际点击数',
  `click_back` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '点击返回数',
  `read_num` int(11) unsigned NOT NULL DEFAULT '0' COMMENT '任务读取数',
  `issue_hourly_task` varchar(256) NOT NULL DEFAULT '' COMMENT '发布的每小时任务曲线数',
  `real_hourly_task` varchar(256) NOT NULL DEFAULT '' COMMENT '实际下发的每小时任务曲线数',
  `task_batch` varchar(256) NOT NULL DEFAULT '' COMMENT '任务的各批次统计',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_task_id` (`task_id`)
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8;
